const d = $input.first().json;
const signal = d.signal || {};

if (signal.action !== 'TRADE') {
  return [{ json: { ...d, skipped: true } }];
}

const now = new Date();
const pad = n => String(n).padStart(2,'0');
const tradeName = `${d.symbol}-${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}-${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}`;
const stopLossPct = Math.abs((signal.stopLoss - signal.entry) / signal.entry) * 100;

const body = {
  parent: { database_id: '' + $env.NOTION_TRADES_DB_ID + '' },
  properties: {
    'Trade Name': { title: [{ text: { content: tradeName } }] },
    'Symbol': { rich_text: [{ text: { content: d.symbol } }] },
    'Side': { select: { name: signal.direction === 'LONG' ? 'LONG' : 'SHORT' } },
    'Status': { select: { name: 'OPEN' } },
    'Entry': { number: signal.entry },
    'Stop Loss': { number: signal.stopLoss },
    'Take Profit': { number: signal.tp1 },
    'Risk Pct': { number: signal.positionSizePct },
    'Stop Loss Pct': { number: stopLossPct },
    'Confidence': { number: signal.confluence },
    'Open Time': { date: { start: now.toISOString() } },
    'Notes': { rich_text: [{ text: { content: `action=${signal.action}|rr=${signal.riskReward}` } }] }
  }
};

const page = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://api.notion.com/v1/pages',
  headers: {
    'Authorization': 'Bearer ' + $env.NOTION_TOKEN + '',
    'Notion-Version': '2022-06-28',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(body)
});

return [{ json: { ...d, notion_page_id: page.id, trade_name: tradeName } }];

const rows = $input.all();
const chatId = $('Set Portfolio Query').first().json.chatId;

if (!rows || rows.length === 0 || !rows[0].json?.id) {
  return [{ json: { chatId, message: '📭 No open trades.' } }];
}

let totalPnl = 0;
const lines = rows.map(r => {
  const t = r.json;
  const pnl = parseFloat(t.unrealized_pnl || 0);
  totalPnl += pnl;
  const emoji = pnl > 0 ? '🟢' : pnl < 0 ? '🔴' : '⚪';
  return `${emoji} *${t.symbol}* ${t.side} @ ${t.entry} | PnL: ${pnl >= 0 ? '+' : ''}${pnl.toFixed(2)}%`;
});

const message = [
  '📊 *Open Positions*',
  ...lines,
  '',
  `Total unrealized: ${totalPnl >= 0 ? '+' : ''}${totalPnl.toFixed(2)}%`
].join('\n');

return [{ json: { chatId, message } }];

const body = {
