const pnlRow = $('Check Daily P&L').first().json;
const openRow = $('Check Open Positions').first().json;

const totalPnl = parseFloat(pnlRow.total_pnl || 0);
const tradeCount = parseInt(pnlRow.trade_count || 0);
const openCount = parseInt(openRow.open_count || 0);

// Block if: daily loss > 3% OR already 3+ open positions
