const tooManyOpen = openCount >= 3;

if (dailyLossBreached || tooManyOpen) {
  return [{ json: {
    allowed: false,
    reason: dailyLossBreached ? `Daily loss limit reached: ${totalPnl.toFixed(2)}%` : `Max open positions reached: ${openCount}`,
    totalPnl, tradeCount, openCount
  }}];
}

return [{ json: { allowed: true, totalPnl, tradeCount, openCount } }];

