const crypto = require('crypto');
const https = require('https');
const API_KEY = '' + $env.BYBIT_API_KEY + '';
const API_SECRET = '' + $env.BYBIT_API_SECRET + '';
const BASE_URL = 'https://api-demo.bybit.com';
const RECV_WINDOW = '5000';

function sign(payload) {
  const ts = Date.now().toString();
  const signStr = ts + API_KEY + RECV_WINDOW + payload;
  const sig = crypto.createHmac('sha256', API_SECRET).update(signStr).digest('hex');
  return { ts, sig };
}

function httpsRequest(method, url, headers, body) {
  return new Promise((resolve, reject) => {
    const urlObj = new URL(url);
    const options = { hostname: urlObj.hostname, path: urlObj.pathname + urlObj.search, method, headers };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { reject(e); } });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

async function get(path, query = '') {
  const { ts, sig } = sign(query);
  const url = query ? `${BASE_URL}${path}?${query}` : `${BASE_URL}${path}`;
  return httpsRequest('GET', url, {
    'X-BAPI-API-KEY': API_KEY, 'X-BAPI-TIMESTAMP': ts,
    'X-BAPI-SIGN': sig, 'X-BAPI-RECV-WINDOW': RECV_WINDOW, 'X-BAPI-SIGN-TYPE': '2'
  });
}

async function post(path, params) {
  const body = JSON.stringify(params);
  const { ts, sig } = sign(body);
  return httpsRequest('POST', `${BASE_URL}${path}`, {
    'Content-Type': 'application/json', 'X-BAPI-API-KEY': API_KEY,
    'X-BAPI-TIMESTAMP': ts, 'X-BAPI-SIGN': sig,
    'X-BAPI-RECV-WINDOW': RECV_WINDOW, 'X-BAPI-SIGN-TYPE': '2'
  }, body);
}

const posRes = await get('/v5/position/list', 'category=linear&settleCoin=USDT');
const positions = posRes?.result?.list?.filter(p => parseFloat(p.size) > 0) || [];

const closed = [];
for (const pos of positions) {
  const closeSide = pos.side === 'Buy' ? 'Sell' : 'Buy';
  await post('/v5/order/cancel-all', { category: 'linear', symbol: pos.symbol });
  const closeRes = await post('/v5/order/create', {
    category: 'linear', symbol: pos.symbol, side: closeSide,
    orderType: 'Market', qty: pos.size, timeInForce: 'GTC',
    reduceOnly: true, positionIdx: 0
  });
  closed.push({
    symbol: pos.symbol, side: pos.side, size: pos.size,
    entryPrice: parseFloat(pos.avgPrice),
    unrealizedPnl: parseFloat(pos.unrealisedPnl),
    closeOrderId: closeRes?.result?.orderId
  });
}

return [{ json: { closed, count: closed.length, sessionDate: new Date().toISOString().slice(0,10) } }];

const headers = {
  'Authorization': 'Bearer ' + $env.NOTION_TOKEN + '',
  'Notion-Version': '2022-06-28',
  'Content-Type': 'application/json'
};

const queryRes = await fetch('https://api.notion.com/v1/databases/' + $env.NOTION_TRADES_DB_ID + '/query', {
  method: 'POST',
  headers,
  body: JSON.stringify({ filter: { property: 'Status', select: { equals: 'OPEN' } } })
});

const queryData = await queryRes.json();
const pages = queryData.results || [];

if (pages.length === 0) {
  return [{ json: { trade_name: null, symbol: null, side: null, entry: 0, pnl_pct: 0 } }];
}

const now = new Date().toISOString();
const results = [];

for (const p of pages) {
  const pr = p.properties;
  const entry = pr['Entry']?.number || 0;
  const existingNotes = pr['Notes']?.rich_text?.[0]?.text?.content || '';

  await fetch(`https://api.notion.com/v1/pages/${p.id}`, {
    method: 'PATCH',
    headers,
    body: JSON.stringify({
      properties: {
        'Status': { select: { name: 'CLOSED' } },
        'Close Time': { date: { start: now } },
        'Close Price': { number: entry },
        'PnL Pct': { number: 0 },
        'RR Achieved': { number: 0 },
        'Notes': { rich_text: [{ text: { content: existingNotes + ' | closed: session_end' } }] }
      }
    })
  });

  results.push({ json: {
    trade_name: pr['Trade Name']?.title?.[0]?.text?.content || '',
    symbol: pr['Symbol']?.rich_text?.[0]?.text?.content || '',
    side: pr['Side']?.select?.name || '',
    entry,
    pnl_pct: 0
  }});
}

return results;

const dbTrades = $input.all();
const phtNow = new Date(Date.now() + 8 * 3600 * 1000);
const dateStr = phtNow.toISOString().slice(0, 10);

let totalPnl = 0;
let wins = 0;
const lines = [];

for (const t of dbTrades) {
  const pnl = parseFloat(t.json.pnl_pct || 0);
  totalPnl += pnl;
  if (pnl > 0) wins++;
  const emoji = pnl > 0 ? '✅' : pnl < 0 ? '❌' : '⏹';
  lines.push(`${emoji} ${t.json.symbol} ${t.json.side}: ${pnl >= 0 ? '+' : ''}${pnl.toFixed(2)}%`);
}

const total = dbTrades.length;
const text = [
  `📊 *London Session Wrap — ${dateStr}*`,
  lines.length > 0 ? lines.join('\n') : 'No trades today.',
  '',
  `Net: ${totalPnl >= 0 ? '+' : ''}${totalPnl.toFixed(2)}% | ${wins}W / ${total - wins}L`,
].join('\n');

return [{ json: { text } }];

